import { type DependencyList, useRef } from 'react';

type EqualityFn = (a: unknown, b: unknown) => boolean;

function depsEqual(a: DependencyList, b: DependencyList, equalityFn: EqualityFn = Object.is) {
  if (a === b) return true;
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    if (!equalityFn(a[i], b[i])) return false;
  }
  return true;
}

export function useDepsChanged(deps: DependencyList, equalityFn: EqualityFn = Object.is): boolean {
  const depsRef = useRef<DependencyList>(deps);
  const changed = !depsEqual(depsRef.current, deps, equalityFn);
  depsRef.current = deps;
  return changed;
}
